package main

import (
	"fmt"
	"net/smtp"
	"strings"
)

// BuildFeedbackEmail constructs an HTML-formatted email body for user feedback
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	if fromAddr == "" || toAddr == "" || userName == "" || subject == "" || feedbackContent == "" {
		return "", fmt.Errorf("all parameters must be provided")
	}

	// Create the HTML email body
	htmlBody := fmt.Sprintf(`
<!DOCTYPE html>
<html>
<head>
    <title>User Feedback</title>
    <style>
        body { font-family: Arial, sans-serif; margin: 20px; }
        .header { background-color: #f5f5f5; padding: 10px; border-radius: 5px; }
        .content { margin-top: 20px; }
        .label { font-weight: bold; color: #333; }
        .value { margin-bottom: 15px; }
    </style>
</head>
<body>
    <div class="header">
        <h2>New User Feedback Received</h2>
    </div>

    <div class="content">
        <p><span class="label">Username:</span> <span class="value">%s</span></p>
        <p><span class="label">Subject:</span> <span class="value">%s</span></p>
        <p><span class="label">Feedback Content:</span></p>
        <div style="border: 1px solid #ccc; padding: 10px; background-color: #f9f9f9; margin-top: 5px;">
            %s
        </div>
    </div>
</body>
</html>`, userName, subject, feedbackContent)

	// Construct the full email headers and body
	var builder strings.Builder
	builder.WriteString(fmt.Sprintf("From: %s\r\n", fromAddr))
	builder.WriteString(fmt.Sprintf("To: %s\r\n", toAddr))
	builder.WriteString(fmt.Sprintf("Subject: %s\r\n", subject))
	builder.WriteString("MIME-Version: 1.0\r\n")
	builder.WriteString("Content-Type: text/html; charset=utf-8\r\n")
	builder.WriteString("\r\n") // End of headers
	builder.WriteString(htmlBody)

	return builder.String(), nil
}

func main() {
	// Example usage
	from := "user@example.com"
	to := "support@example.com"
	userName := "John Doe"
	subject := "Issue with login functionality"
	feedbackContent := "I'm having trouble logging into my account. The login button doesn't seem to respond when I click it."

	emailBody, err := BuildFeedbackEmail(from, to, userName, subject, feedbackContent)
	if err != nil {
		fmt.Printf("Error building email: %v\n", err)
		return
	}

	fmt.Println("Generated Email Body:")
	fmt.Println(emailBody)
}

