package main

import (
	"encoding/base64"
	"fmt"
	"html"
	"net/mail"
	"strings"
)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate email addresses format (optional but good practice)
	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Sanitize inputs to prevent header injection
	if strings.ContainsAny(userName, "\r\n") {
		return "", fmt.Errorf("userName contains invalid characters")
	}
	if strings.ContainsAny(subject, "\r\n") {
		return "", fmt.Errorf("subject contains invalid characters")
	}
	if strings.ContainsAny(feedbackContent, "\r\n") {
		return "", fmt.Errorf("feedbackContent contains invalid characters")
	}

	// Use html.EscapeString to properly escape HTML entities
	sanitizedUserName := html.EscapeString(userName)
	sanitizedSubject := html.EscapeString(subject)
	sanitizedFeedbackContent := html.EscapeString(feedbackContent)

	// Construct email headers
	emailSubject := fmt.Sprintf("Feedback: %s", sanitizedSubject)

	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\nContent-Transfer-Encoding: base64\r\n\r\n",
		fromAddr,
		toAddr,
		emailSubject,
	)

	// Construct HTML body
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
</body>
</html>`,
		sanitizedUserName,
		sanitizedSubject,
		sanitizedFeedbackContent,
	)

	// Encode the HTML body using base64
	encodedBody := base64.StdEncoding.EncodeToString([]byte(htmlBody))

	// Combine headers and encoded body
	emailMessage := headers + encodedBody

	return emailMessage, nil
}

// htmlEscape sanitizes input strings to prevent XSS attacks
func htmlEscape(s string) string {
	s = strings.ReplaceAll(s, "&", "&amp;")
	s = strings.ReplaceAll(s, "<", "&lt;")
	s = strings.ReplaceAll(s, ">", "&gt;")
	s = strings.ReplaceAll(s, "\"", "&quot;")
	s = strings.ReplaceAll(s, "'", "&#x27;")
	return s
}

