package main

import (
	"encoding/base64"
	"fmt"
	"html"
	"net/mail"
	"strings"
)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate email addresses format (optional but good practice)
	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Sanitize inputs to prevent header injection
	userName = sanitizeInput(userName)
	subject = sanitizeInput(subject)
	feedbackContent = sanitizeInput(feedbackContent)

	// Construct email headers
	emailSubject := fmt.Sprintf("Feedback: %s", subject)

	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\nContent-Transfer-Encoding: quoted-printable\r\n\r\n",
		fromAddr,
		toAddr,
		emailSubject,
	)

	// Construct HTML body with sanitized inputs
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
</body>
</html>`,
		html.EscapeString(userName),
		html.EscapeString(subject),
		html.EscapeString(feedbackContent),
	)

	// Encode the body using quoted-printable
	encodedBody := quotedPrintableEncode(htmlBody)

	// Combine headers and encoded body
	emailMessage := headers + encodedBody

	return emailMessage, nil
}

// sanitizeInput removes any potential header injection characters
func sanitizeInput(input string) string {
	// Remove carriage returns and newlines which could be used for email header injection
	input = strings.ReplaceAll(input, "\r", "")
	input = strings.ReplaceAll(input, "\n", "")
	return input
}

// quotedPrintableEncode encodes the input string according to quoted-printable encoding rules
func quotedPrintableEncode(s string) string {
	var result strings.Builder
	for i := 0; i < len(s); i++ {
		c := s[i]
		switch c {
		case '\t', ' ':
			// Spaces and tabs at the end of lines need to be encoded
			if i+1 < len(s) && (s[i+1] == '\r' || s[i+1] == '\n') {
				result.WriteString("=" + fmt.Sprintf("%02X", c))
			} else {
				result.WriteByte(c)
			}
		case '=':
			result.WriteString("=3D")
		case '\r':
			if i+1 < len(s) && s[i+1] == '\n' {
				result.WriteString("\r\n")
				i++ // skip the next character since we've already processed it
			} else {
				result.WriteString("=0D")
			}
		case '\n':
			result.WriteString("\r\n")
		default:
			if c < 32 || c > 126 { // Non-printable or extended ASCII characters (excluding DEL)
				result.WriteString("=" + fmt.Sprintf("%02X", c))
			} else {
				result.WriteByte(c)
			}
		}
	}
	return result.String()
}

