// replaceAll is a simple helper function to replace all occurrences of old string with new string
func replaceAll(s, old, new string) string {
	if old == "" {
		return s
	}

	// Count occurrences to pre-allocate memory for the result
	count := 0
	start := 0
	for {
		pos := indexOf(s, start, old)
		if pos == -1 {
