		}
		count++
		start = pos + len(old)
	}

	if count == 0 {
		return s
	}

	// Build the result string
	result := make([]byte, 0, len(s)+count*(len(new)-len(old)))
	start = 0
	for {
		pos := indexOf(s, start, old)
		if pos == -1 {
			result = append(result, s[start:]...)
			break
		}
		result = append(result, s[start:pos]...)
		result = append(result, new...)
		start = pos + len(old)
	}

	return string(result)
}

