)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate email addresses format (optional but good practice)
	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Sanitize inputs to prevent header injection
	userName = sanitizeHeader(userName)
	subject = sanitizeHeader(subject)
	feedbackContent = sanitizeHeader(feedbackContent)

	// Construct email headers
	emailSubject := fmt.Sprintf("Feedback: %s", subject)

	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\nContent-Transfer-Encoding: quoted-printable\r\n\r\n",
		fromAddr,
		toAddr,
		emailSubject,
	)

	// Use html.EscapeString to properly escape user input for HTML content to prevent XSS
	safeUserName := html.EscapeString(userName)
	safeSubject := html.EscapeString(subject)
	safeFeedbackContent := html.EscapeString(feedbackContent)

	// Construct HTML body
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
</body>
</html>`,
		safeUserName,
		safeSubject,
		safeFeedbackContent,
	)

	// Encode the HTML body using quoted-printable encoding
	encodedBody := quotedPrintableEncode(htmlBody)

	// Combine headers and encoded body
	emailMessage := headers + encodedBody

	return emailMessage, nil
}

// sanitizeHeader removes any newline characters that could be used for header injection
func sanitizeHeader(header string) string {
	// Remove any carriage return or newline characters to prevent header injection
	header = strings.ReplaceAll(header, "\r", "")
	header = strings.ReplaceAll(header, "\n", "")
	return header
}

// quotedPrintableEncode encodes the input string according to the quoted-printable encoding scheme
func quotedPrintableEncode(input string) string {
	var result strings.Builder
	for _, r := range []byte(input) {
		c := rune(r)
		switch {
		case c == ' ' || c == '\t' || (c >= 33 && c <= 126 && c != '=' && c != '?' && c != '_'):
			result.WriteRune(c)
		default:
			result.WriteString(fmt.Sprintf("=%02X", r))
		}
	}
	return result.String()
}

