package main

import (
	"encoding/base64"
	"fmt"
	"mime"
	"net/mail"
	"strings"
)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate email addresses format (optional but good practice)
	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Sanitize inputs to prevent header injection
	userName = strings.ReplaceAll(userName, "\n", "")
	userName = strings.ReplaceAll(userName, "\r", "")
	subject = strings.ReplaceAll(subject, "\n", "")
	subject = strings.ReplaceAll(subject, "\r", "")
	feedbackContent = strings.ReplaceAll(feedbackContent, "\n", "")
	feedbackContent = strings.ReplaceAll(feedbackContent, "\r", "")

	// Encode subject using MIME encoding to handle special characters safely
	encodedSubject := mime.QEncoding.Encode("utf-8", fmt.Sprintf("Feedback: %s", subject))

	// Construct email headers
	headers := make(map[string]string)
	headers["From"] = fromAddr
	headers["To"] = toAddr
	headers["Subject"] = encodedSubject
	headers["MIME-Version"] = "1.0"
	headers["Content-Type"] = "text/html; charset=UTF-8"

	// Build the header string
	var headerString string
	for key, value := range headers {
		headerString += fmt.Sprintf("%s: %s\r\n", key, value)
	}
	headerString += "\r\n" // End of headers

	// Escape HTML content to prevent XSS
	sanitizedUserName := fmt.Sprintf("%s", htmlEscape(userName))
	sanitizedSubject := fmt.Sprintf("%s", htmlEscape(subject))
	sanitizedFeedbackContent := fmt.Sprintf("%s", htmlEscape(feedbackContent))

	// Construct HTML body
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
</body>
</html>`,
		sanitizedUserName,
		sanitizedSubject,
		sanitizedFeedbackContent,
	)

	// Combine headers and body
	emailMessage := headerString + htmlBody

	return emailMessage, nil
}

// htmlEscape escapes HTML special characters to prevent XSS attacks
func htmlEscape(s string) string {
	s = strings.ReplaceAll(s, "&", "&amp;")
	s = strings.ReplaceAll(s, "<", "&lt;")
	s = strings.ReplaceAll(s, ">", "&gt;")
	s = strings.ReplaceAll(s, `"`, "&quot;")
	s = strings.ReplaceAll(s, "'", "&#39;")
	return s
}

